(window.webpackJsonp=window.webpackJsonp||[]).push([[482],{1109:function(n,r){n.exports='\x3c!-- \r\ntitle: 01-React配置\r\nsort: \r\n--\x3e \r\n\r\n- # React入门\r\n\r\n  ## NodeJS\r\n\r\n  > `node.js`是基于chrome v8引擎的JS运行环境\r\n  >\r\n  > 前端开发环境、服务端编程语言\r\n\r\n  ### Npm\r\n\r\n  > [npmjs](https://www.npmjs.com/)\r\n\r\n  ```powershell\r\n  node -v\r\n  node\t# 进入JS运行环境\r\n  \r\n  npm -v\r\n  npm init\r\n  npm install [-g]\t# 全局安装\r\n  # 换源\r\n  npm config set registry https://registry.npm.taobao.org\r\n  # 发布包时换回原来的源\r\n  npm config set registry https://registry.npmjs.org\r\n  # 发布插件\r\n  npm adduser | npm publish\r\n  \r\n# 使用\r\n  npm init\r\n# 保存到package.json\r\n  # 下次直接install\r\n  npm install react --save\r\n  ```\r\n  \r\n  ### Yarn\r\n\r\n  > `npm i yarn -g`\r\n  >\r\n  > 弥补了npm的一些缺陷\r\n  >\r\n  > [中文文档](https://yarn.bootcss.com/)\r\n  \r\n  ```powershell\r\n  npm i yarn@1.22.0 -g \t# 安装特定版本\r\n  npm upgrade yarn -g\t\t# 更新\r\n  \r\n  yarn config set registry https://registry.npm.taobao.org\r\n  \r\n  yarn -v\r\n  # 初始化项目\r\nyarn init\r\n  yarn isntall\r\nyarn add/remove # 添加依赖包\r\n  yarn publish\r\n  yarn run\r\n  ```\r\n  \r\n  > 搭建环境\r\n  \r\n  ```powershell\r\n  yarn init\r\nyarn add react --save\t# 添加新插件\r\n  yarn install\t\t# 拉取旧插件\r\n\r\n  yarn login\t\t\t# 登录\r\n  yarn logout\t\t\t# 登出\r\n  ```\r\n  \r\n  > 编辑Package\r\n  \r\n  ```json\r\n    "scripts": {\r\n      "ver": "npm -v"\r\n    },\r\n  \r\n  // yarn run server\r\n  ```\r\n'}}]);